// EventAPI Sink IDL
//
// 定义事件与下游数据接收端（StarRocks、MySQL 等）的字段映射，
// 用于自动生成 DDL 建表语句和 Flink SQL pipeline。
//
// =====================================================================
// 惯例
// =====================================================================
//
// sink 与 operation 写在同一个 SEND rpc 上：
//
//   rpc SendOrder(OrderEvent) returns (google.protobuf.Empty) {
//     option (eventapi.v1.operation) = { ... };  // 怎么发
//     option (eventapi.v1.sink) = { ... };        // 发完去哪
//   }
//
// 规则：
//   - sink 只放在 action: SEND 的 rpc 上
//   - RECEIVE rpc 不写 sink
//   - 一个 rpc 可配多个 sink（同一消息落多个目标）
//
// =====================================================================
// 完整示例
// =====================================================================
//
//   rpc SendOrder(OrderEvent) returns (google.protobuf.Empty) {
//     option (eventapi.v1.operation) = {
//       action: SEND
//       channel: { address: "order.events" }
//     };
//     option (eventapi.v1.sink) = {
//       target: SINK_TYPE_STARROCKS
//       database: "analytics"
//       table: "order_events"
//       source_topic: "order.events"
//       event_data_content_type: CONTENT_TYPE_JSON
//       primary_key: ["event_id"]
//       partition_key: ["event_time"]
//       mapping: [
//         // CloudEvent header 字段
//         { header_path: "ce_id",      target_column: "event_id",   type: COLUMN_TYPE_VARCHAR, not_null: true },
//         { header_path: "ce_type",    target_column: "event_type", type: COLUMN_TYPE_VARCHAR },
//         { header_path: "ce_source",  target_column: "event_source", type: COLUMN_TYPE_VARCHAR },
//         { header_path: "ce_time",    target_column: "event_time", type: COLUMN_TYPE_TIMESTAMP },
//         { header_path: "ce_subject", target_column: "subject",    type: COLUMN_TYPE_VARCHAR },
//
//         // 消息体 data 字段（JSON 路径）
//         { data_path: "$.order_id",     target_column: "order_id",    type: COLUMN_TYPE_VARCHAR, not_null: true },
//         { data_path: "$.user_id",      target_column: "user_id",     type: COLUMN_TYPE_VARCHAR },
//         { data_path: "$.order_amount", target_column: "order_amount",type: COLUMN_TYPE_BIGINT },
//         { data_path: "$.order_status", target_column: "order_status",type: COLUMN_TYPE_VARCHAR },
//
//         // 嵌套提取：header 值是 JSON 时
//         { header_path: "$.ce_source.tenant", target_column: "tenant_id", type: COLUMN_TYPE_VARCHAR }
//       ]
//     };
//   }
//
// =====================================================================
// 字段映射规则
// =====================================================================
//
// header_path:
//   - 直接读取: "ce_id", "ce_type", "ce_source", "ce_time", "ce_subject"
//   - 嵌套提取: "$.ce_source.tenant" → JSON_VALUE(ce_source, '$.tenant')
//
// data_path:
//   - CONTENT_TYPE_JSON:  Flink 自动反序列化，直接映射列
//   - 其他格式:           JSON_VALUE(value, '$.field') 手动解析
//
// =====================================================================
// 自动推断
// =====================================================================
//
// 生成器会自动遍历 RPC 入参 Message 的所有字段，
// 对于未在 mapping 中显式声明 data_path 的字段，按以下规则自动补全：
